Bash(powershell -Command "
Get-NetTCPConnection -State Listen -ErrorAction SilentlyContinue | 
  Where-Object { \\$_.OwningProcess -in \(Get-Process java,node -ErrorAction SilentlyContinue | Select-Object -ExpandProperty Id\) } |
  ForEach-Object { 
    \\$proc = Get-Process -Id \\$_.OwningProcess -ErrorAction SilentlyContinue
    [PSCustomObject]@{ Port=\\$_.LocalPort; PID=\\$_.OwningProcess; Name=\\$proc.Name }
  } | Sort-Object Port | Format-Table
")
